SELECT acs_estimate
FROM acs_data
WHERE state_id = 1 AND county_id = 0;

SELECT AVG(fmr_pct_chg) AS avg_fmr_pct_chg
FROM fmr_data
WHERE countyname = 'Autauga County';

SELECT fmr_id, metro
FROM fmr_data
WHERE fmr_type = (SELECT fmr_type_id FROM fmr_types WHERE fmr_type_name = '50th percentile');

SELECT fmr_type_name
FROM fmr_types
WHERE fmr_type_id = 1;

SELECT areaname, state_alpha, fmr_pct_chg, fmr_dollar_chg
FROM fmr_data
WHERE fmr_pct_chg = (SELECT MAX(fmr_pct_chg) FROM fmr_data);
